SELECT COUNT(*) AS new_york_elections
FROM goodparty_data_catalog.mart_civics.election
WHERE state = 'NY';

SELECT COUNT(*) AS state_legislative_elections
FROM goodparty_data_catalog.mart_civics.election
WHERE candidate_office IN ('State Representative', 'State Senate');

SELECT COUNT(*) AS users_ytd
FROM goodparty_data_catalog.mart_civics.users
WHERE created_at >= date_trunc('YEAR', CURRENT_DATE());

SELECT COUNT(*) AS pledged_candidates
FROM goodparty_data_catalog.mart_civics.users
WHERE has_pledged_campaign = TRUE;

SELECT COUNT(*) AS users_with_campaign
FROM goodparty_data_catalog.mart_civics.users
WHERE is_win_user = TRUE;

SELECT COUNT(*) AS win_icp_eligible_candidacies
FROM goodparty_data_catalog.mart_civics.candidacy
WHERE is_win_icp = TRUE;

SELECT COUNT(*) AS serve_users
FROM goodparty_data_catalog.mart_civics.users
WHERE is_serve_user = TRUE;

